    51→class ProcessWrap : public HandleWrap {
    52→ public:
    53→  static void Initialize(Local<Object> target,
    54→                         Local<Value> unused,
    55→                         Local<Context> context,
    56→                         void* priv) {
    57→    Environment* env = Environment::GetCurrent(context);
    58→    Isolate* isolate = env->isolate();
    59→    Local<FunctionTemplate> constructor = NewFunctionTemplate(isolate, New);
    60→    constructor->InstanceTemplate()->SetInternalFieldCount(
    61→        ProcessWrap::kInternalFieldCount);
    62→
    63→    constructor->Inherit(HandleWrap::GetConstructorTemplate(env));
    64→
    65→    SetProtoMethod(isolate, constructor, "spawn", Spawn);
    66→    SetProtoMethod(isolate, constructor, "kill", Kill);
    67→
    68→    SetConstructorFunction(context, target, "Process", constructor);
    69→  }
    70→
    71→  static void RegisterExternalReferences(ExternalReferenceRegistry* registry) {
    72→    registry->Register(New);
    73→    registry->Register(Spawn);
    74→    registry->Register(Kill);
    75→  }
    76→
    77→  SET_NO_MEMORY_INFO()
    78→  SET_MEMORY_INFO_NAME(ProcessWrap)
    79→  SET_SELF_SIZE(ProcessWrap)
    80→
    81→ private:
    82→  static void New(const FunctionCallbackInfo<Value>& args) {
    83→    // This constructor should not be exposed to public javascript.
    84→    // Therefore we assert that we are not trying to call this as a
    85→    // normal function.
    86→    CHECK(args.IsConstructCall());
    87→    Environment* env = Environment::GetCurrent(args);
    88→    new ProcessWrap(env, args.This());
    89→  }
    90→
    91→  ProcessWrap(Environment* env, Local<Object> object)
    92→      : HandleWrap(env,
    93→                   object,
    94→                   reinterpret_cast<uv_handle_t*>(&process_),
    95→                   AsyncWrap::PROVIDER_PROCESSWRAP) {
    96→    MarkAsUninitialized();
    97→  }
    98→
    99→  static uv_stream_t* StreamForWrap(Environment* env, Local<Object> stdio) {
   100→    Local<String> handle_key = env->handle_string();
   101→    // This property has always been set by JS land if we are in this code path.
   102→    Local<Object> handle =
   103→        stdio->Get(env->context(), handle_key).ToLocalChecked().As<Object>();
   104→
   105→    uv_stream_t* stream = LibuvStreamWrap::From(env, handle)->stream();
   106→    CHECK_NOT_NULL(stream);
   107→    return stream;
   108→  }
   109→
   110→  static void ParseStdioOptions(Environment* env,
   111→                                Local<Object> js_options,
   112→                                uv_process_options_t* options) {
   113→    Local<Context> context = env->context();
   114→    Local<String> stdio_key = env->stdio_string();
   115→    Local<Array> stdios =
   116→        js_options->Get(context, stdio_key).ToLocalChecked().As<Array>();
   117→
   118→    uint32_t len = stdios->Length();
   119→    options->stdio = new uv_stdio_container_t[len];
   120→    options->stdio_count = len;
   121→
   122→    for (uint32_t i = 0; i < len; i++) {
   123→      Local<Object> stdio =
   124→          stdios->Get(context, i).ToLocalChecked().As<Object>();
   125→      Local<Value> type =
   126→          stdio->Get(context, env->type_string()).ToLocalChecked();
   127→
   128→      if (type->StrictEquals(env->ignore_string())) {
   129→        options->stdio[i].flags = UV_IGNORE;
   130→      } else if (type->StrictEquals(env->pipe_string())) {
   131→        options->stdio[i].flags = static_cast<uv_stdio_flags>(
   132→            UV_CREATE_PIPE | UV_READABLE_PIPE | UV_WRITABLE_PIPE);
   133→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   134→      } else if (type->StrictEquals(env->overlapped_string())) {
   135→        options->stdio[i].flags = static_cast<uv_stdio_flags>(
   136→            UV_CREATE_PIPE | UV_READABLE_PIPE | UV_WRITABLE_PIPE |
   137→            UV_OVERLAPPED_PIPE);
   138→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   139→      } else if (type->StrictEquals(env->wrap_string())) {
   140→        options->stdio[i].flags = UV_INHERIT_STREAM;
   141→        options->stdio[i].data.stream = StreamForWrap(env, stdio);
   142→      } else {
   143→        Local<String> fd_key = env->fd_string();
   144→        Local<Value> fd_value = stdio->Get(context, fd_key).ToLocalChecked();
   145→        CHECK(fd_value->IsNumber());
   146→        int fd = static_cast<int>(fd_value.As<Integer>()->Value());
   147→        options->stdio[i].flags = UV_INHERIT_FD;
   148→        options->stdio[i].data.fd = fd;
   149→      }
   150→    }
   151→  }
   152→
   153→  static void Spawn(const FunctionCallbackInfo<Value>& args) {
   154→    Environment* env = Environment::GetCurrent(args);
   155→    Local<Context> context = env->context();
   156→    ProcessWrap* wrap;
   157→    ASSIGN_OR_RETURN_UNWRAP(&wrap, args.This());
   158→    THROW_IF_INSUFFICIENT_PERMISSIONS(
   159→        env, permission::PermissionScope::kChildProcess, "");
   160→    int err = 0;
   161→
   162→    Local<Object> js_options =
   163→        args[0]->ToObject(env->context()).ToLocalChecked();
   164→
   165→    uv_process_options_t options;
   166→    memset(&options, 0, sizeof(uv_process_options_t));
   167→
   168→    options.exit_cb = OnExit;
   169→
   170→    // options.uid
   171→    Local<Value> uid_v =
   172→        js_options->Get(context, env->uid_string()).ToLocalChecked();
   173→    if (!uid_v->IsUndefined() && !uid_v->IsNull()) {
   174→      CHECK(uid_v->IsInt32());
   175→      const int32_t uid = uid_v.As<Int32>()->Value();
   176→      options.flags |= UV_PROCESS_SETUID;
   177→      options.uid = static_cast<uv_uid_t>(uid);
   178→    }
   179→
   180→    // options.gid
   181→    Local<Value> gid_v =
   182→        js_options->Get(context, env->gid_string()).ToLocalChecked();
   183→    if (!gid_v->IsUndefined() && !gid_v->IsNull()) {
   184→      CHECK(gid_v->IsInt32());
   185→      const int32_t gid = gid_v.As<Int32>()->Value();
   186→      options.flags |= UV_PROCESS_SETGID;
   187→      options.gid = static_cast<uv_gid_t>(gid);
   188→    }
   189→
   190→    // TODO(bnoordhuis) is this possible to do without mallocing ?
   191→
   192→    // options.file
   193→    Local<Value> file_v =
   194→        js_options->Get(context, env->file_string()).ToLocalChecked();
   195→    CHECK(file_v->IsString());
   196→    node::Utf8Value file(env->isolate(), file_v);
   197→    options.file = *file;
   198→
   199→    // Undocumented feature of Win32 CreateProcess API allows spawning
   200→    // batch files directly but is potentially insecure because arguments
   201→    // are not escaped (and sometimes cannot be unambiguously escaped),
   202→    // hence why they are rejected here.
   203→#ifdef _WIN32
   204→    if (IsWindowsBatchFile(options.file))
   205→      err = UV_EINVAL;
   206→#endif
   207→
   208→    // options.args
   209→    Local<Value> argv_v =
   210→        js_options->Get(context, env->args_string()).ToLocalChecked();
   211→    if (!argv_v.IsEmpty() && argv_v->IsArray()) {
   212→      Local<Array> js_argv = argv_v.As<Array>();
   213→      int argc = js_argv->Length();
   214→      CHECK_LT(argc, INT_MAX);  // Check for overflow.
   215→
   216→      // Heap allocate to detect errors. +1 is for nullptr.
   217→      options.args = new char*[argc + 1];
   218→      for (int i = 0; i < argc; i++) {
   219→        node::Utf8Value arg(env->isolate(),
   220→                            js_argv->Get(context, i).ToLocalChecked());
   221→        options.args[i] = strdup(*arg);
   222→        CHECK_NOT_NULL(options.args[i]);
   223→      }
   224→      options.args[argc] = nullptr;
   225→    }
   226→
   227→    // options.cwd
   228→    Local<Value> cwd_v =
   229→        js_options->Get(context, env->cwd_string()).ToLocalChecked();
   230→    node::Utf8Value cwd(env->isolate(),
   231→                        cwd_v->IsString() ? cwd_v : Local<Value>());
   232→    if (cwd.length() > 0) {
   233→      options.cwd = *cwd;
   234→    }
   235→
   236→    // options.env
   237→    Local<Value> env_v =
   238→        js_options->Get(context, env->env_pairs_string()).ToLocalChecked();
   239→    if (!env_v.IsEmpty() && env_v->IsArray()) {
   240→      Local<Array> env_opt = env_v.As<Array>();
   241→      int envc = env_opt->Length();
   242→      CHECK_LT(envc, INT_MAX);            // Check for overflow.
   243→      options.env = new char*[envc + 1];  // Heap allocated to detect errors.
   244→      for (int i = 0; i < envc; i++) {
   245→        node::Utf8Value pair(env->isolate(),
   246→                             env_opt->Get(context, i).ToLocalChecked());
   247→        options.env[i] = strdup(*pair);
   248→        CHECK_NOT_NULL(options.env[i]);
   249→      }
   250→      options.env[envc] = nullptr;
   251→    }
   252→
   253→    // options.stdio
   254→    ParseStdioOptions(env, js_options, &options);
   255→
   256→    // options.windowsHide
   257→    Local<Value> hide_v =
   258→        js_options->Get(context, env->windows_hide_string()).ToLocalChecked();
   259→
   260→    if (hide_v->IsTrue()) {
   261→      options.flags |= UV_PROCESS_WINDOWS_HIDE;
   262→    }
   263→
   264→    if (env->hide_console_windows()) {
   265→      options.flags |= UV_PROCESS_WINDOWS_HIDE_CONSOLE;
